import React from 'react';
import { useNavigate } from 'react-router-dom';

const CameraUpload = () => {
  const navigate = useNavigate();

  return (
    <div className="camera-upload">
      <button className="back-btn" onClick={() => navigate('/input')}>← Back</button>
      <h2 className="montserrat-alternates-semibold">Upload Your Cube</h2>
      <p className="montserrat-alternates-regular">Hello world - Camera upload coming soon!</p>
    </div>
  );
};

export default CameraUpload;
